  ('elementary-0489de64-moex-00621', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '公路主管機關，為公路養護、修建及安全管理所需經費，得徵收汽車燃料使用費；其徵收費率至多不得 超過燃料進口或出廠價格多少百分比？', '["百分之二十五", "百分之十五", "百分之二十", "百分之三十"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00622', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '依民用航空法第98條規定，因航空器失事，致其所載人員失蹤，其失蹤人於失蹤滿多久後，法院得因利 害關係人或檢察官之聲請，為死亡之宣告？', '["6個月", "1年", "2年", "3年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00623', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列關於船舶貨物裝卸承攬業及船舶理貨業管理之敘述何者錯誤？', '["船舶貨物裝卸承攬業、船舶理貨業之營業許可證，不得出借、出租或轉讓", "船舶理貨業應自取得許可證之日起6個月內開始營業，屆期未開始營業者，得申請展延，最多以兩次為限", "船舶理貨業營業後，連續6個月以上無營運實績者，得由航港局廢止其營業許可並註銷其許可證", "航港局或指定機關得隨時派員前往船舶貨物裝卸承攬業為必要之查驗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00624', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列何者並非普通航空業之業務？', '["空中遊覽", "餐點裝卸、機艙清潔", "勘察、照測、消防、搜尋、救護、拖吊、噴灑", "商務專機"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00625', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列關於大眾捷運系統由民間投資建設之規定，何者錯誤？', '["公司最低實收資本額不得低於新臺幣10億元", "申請人申請投資捷運建設計畫時，其資本額應為總工程經費百分之二十以上", "取得最優申請人資格者應於 6 個月內完成最低實收資本額為總工程經費百分之二十五以上之股份有限 公司設立登記", "民間機構在籌辦、興建及營運時期，其自有資金之最低比率，均應維持在百分之二十五以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00626', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '大眾捷運系統之營運，旅客運價如法令另有規定予以優待者，應由其主管機關編列預算補貼，請問以下 何者符合此一要件？', '["定期票", "敬老票", "團體票", "一日票"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00627', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列關於船務代理業與海運承攬運送業之敘述何者錯誤？', '["經營海運承攬運送業者於申請核發許可證時，應繳交一定金額之保證金，或依主管機關所定保險金額 投保承攬運送責任保險", "外國籍海運承攬運送業不得在我國境內營業", "船務代理業所代理之外國籍船舶運送業，在我國境內攬運之客貨，發生運送糾紛或爭議，船務代理業 應協助妥善處理", "海運承攬運送業除船舶運送業兼營者外，不得光船承租船舶，運送其所承攬貨物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00628', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列關於停車場法之敘述何者錯誤？', '["公私有建築物新建或改建時，投資增設停車空間開放供公眾使用，但仍應受建築法令有關高度及容積 率之限制", "都市計畫公共停車場用地，除作停車場使用外，得作為商場百貨業等立體多目標使用", "市場、公園、綠地、廣場、學校、高架道路之地下或地上層，得以多目標使用方式附建停車場", "加油站、道路、車站、變電所、污水處理設施、焚化場之地下或地上層，得以多目標使用方式附建停 車場"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00629', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '以下關於路邊停車場費率之說明何者錯誤？', '["停車費得以計時或以計次方式收取", "停車費得視地區交通狀況，採取停車時間累進方式收費", "停車費得視地區交通狀況，限制可供公眾使用之停車時間", "停車費採取計時收取時，得以20分鐘為計費單位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00630', 'elementary-0489de64', 'elementary-0489de64-moex-111-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列何者並非臺鐵營運之客運路線', '["臺南沙崙支線", "新竹六家支線", "海科館深澳線", "阿里山森林鐵路"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:00+00:00", "source_pdf_sha1": "561afc2a9aa9", "answer_pdf_sha1": "dacf140a040e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
